function DashboardVideoClient({ video }: { video: any }) {
  const [liked, setLiked] = useState(false)

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-8">
      {/* Back button */}
      <Link href="/dashboard/beginner">
        <Button variant="ghost" size="sm">
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back
        </Button>
      </Link>

      <div className="grid lg:grid-cols-1 gap-6">
        {/* Video Player Section */}
        <div className="space-y-4">
          {/* Large Video Player */}
          <Card className="overflow-hidden border-0 shadow-lg">
            <div className="relative aspect-video bg-black">
              <video className="w-full h-full" controls poster={video.thumbnail}>
                <source src={video.thumbnail} type="video/mp4" />
              </video>
            </div>
          </Card>

          {/* Video Info */}
          <div className="space-y-3">
            <h1 className="text-2xl lg:text-3xl font-bold text-foreground">{video.title}</h1>

            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-muted overflow-hidden">
                <img
                  src={video.instructorAvatar || "/placeholder.svg?height=40&width=40"}
                  alt={video.instructor}
                  className="w-full h-full object-cover"
                />
              </div>
              <span className="font-medium text-foreground">{video.instructor}</span>
            </div>

            <div className="flex items-center gap-6 text-sm text-muted-foreground">
              <div className="flex items-center gap-2">
                <Eye className="w-4 h-4" />
                <span>{video.views}</span>
              </div>
              <div className="flex items-center gap-2">
                <Heart className={`w-4 h-4 ${liked ? "fill-primary text-primary" : ""}`} />
                <span>{liked ? Number(video.likes) + 1 : video.likes}</span>
              </div>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setLiked(!liked)}
                className="h-auto p-0 hover:bg-transparent"
              >
                <Heart className={`w-5 h-5 ${liked ? "fill-primary text-primary" : ""}`} />
              </Button>
            </div>
          </div>

          {video.sections && video.sections.length > 0 && (
            <div className="space-y-3 pt-4">
              <h2 className="text-lg font-semibold text-foreground">Workout Sections</h2>
              <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
                {video.sections.map((section: any, index: number) => (
                  <Card
                    key={index}
                    className="p-4 hover:shadow-md transition-shadow cursor-pointer border-2 hover:border-primary"
                  >
                    <div className="space-y-2">
                      <div className="inline-block px-2 py-1 bg-primary/10 text-primary text-xs font-semibold rounded">
                        {section.time}
                      </div>
                      <h3 className="font-medium text-sm text-foreground leading-snug">{section.title}</h3>
                    </div>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* Description */}
          <div className="pt-4 space-y-2">
            <h2 className="text-lg font-semibold text-foreground">About this workout</h2>
            <p className="text-muted-foreground leading-relaxed">{video.description}</p>
          </div>
        </div>
      </div>
    </div>
  )
}

export default async function DashboardVideoPage({ params }: { params: { id: string } }) {
  const { id } = params
  const video = videoDatabase[id] || videoDatabase["bm1"]

  return <DashboardVideoClient video={video} />
}
